import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import type { CatalogUiField, CatalogUiSchema } from '../../../types/catalogUiSchema';
export type PaginatedList<T> = {
  items: T[];
  totalCount: number;
  page: number;
  pageSize: number;
};

type SearchParams = {
  search?: string;
  page?: number;
  pageSize?: number;
};

export type CatalogSearchAdapter<T> = (params: SearchParams) => Promise<PaginatedList<T>>;

function variantFor(field: CatalogUiField): 'badge' | 'primary' | 'meta' {
  const v = field.lookup?.variant;
  if (v === 'badge' || v === 'primary' || v === 'meta') return v;
  if (field.control === 'CODE') return 'badge';
  return 'primary';
}

/**
 * Build SearchInputConfig from BE ui-schema — columns/widths follow «Sửa config».
 * Rule: catalog-lookup-from-schema.md
 */
export function mapCatalogSchemaToSearchConfig<T extends Record<string, unknown>>(
  schema: CatalogUiSchema,
  options: {
    search: CatalogSearchAdapter<T>;
    getItemKey: (item: T) => string;
    getPrimaryDisplay?: (item: T) => string;
    getSecondaryDisplay?: (item: T) => string;
  },
): SearchInputConfig<T> {
  const lookupFields = schema.fields
    .filter(f => f.lookup?.visible)
    .sort((a, b) => (a.lookup?.order ?? 0) - (b.lookup?.order ?? 0));

  const primaryKey = schema.lookup.primaryDisplayKey;
  const secondaryKey = schema.lookup.secondaryDisplayKey ?? 'name';

  return {
    api: {
      getItemKey: options.getItemKey,
      search: async ({ search, page, pageSize }) => {
        const data = await options.search({ search, page, pageSize });
        const totalPages = Math.max(1, Math.ceil(data.totalCount / (data.pageSize || 20)));
        return { items: data.items, page: data.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: options.getPrimaryDisplay
        ?? (item => String(item[primaryKey] ?? '')),
      getSecondaryDisplay: options.getSecondaryDisplay
        ?? (item => String(item[secondaryKey] ?? '')),
    },
    columns: lookupFields.map(f => ({
      key: f.key,
      variant: variantFor(f),
      width: f.lookup?.width ?? undefined,
      render: (item: T) => {
        const v = item[f.key];
        if (v == null || v === '') return '—';
        return String(v);
      },
    })),
    header: {
      columns: lookupFields.map(f => ({ key: f.key, label: f.label })),
    },
    dropdownMatch: (schema.lookup.dropdownMatch as 'row' | 'container' | 'lookup') ?? 'row',
    dropdownMinWidth: schema.lookup.dropdownMinWidth ?? undefined,
    texts: { empty: 'Không có bản ghi nào' },
  };
}
