import { apiClient, unwrap, type BffResponse } from '../api';

const BASE = '/master/departments';

export type DepartmentCatalogRow = {
  id: string;
  code: string;
  name: string;
  isActive: boolean;
  [key: string]: unknown;
};

export type DepartmentCatalogListParams = {
  search?: string;
  page?: number;
  pageSize?: number;
};

type PaginatedApi<T> = {
  items: T[];
  total?: number;
  totalCount?: number;
  page: number;
  pageSize: number;
};

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const departmentCatalogEndpoint = {
  getList: async (params?: DepartmentCatalogListParams) => {
    const qs = buildQs({
      search: params?.search,
      page: params?.page ?? 1,
      pageSize: params?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PaginatedApi<DepartmentCatalogRow>>>(
      `${BASE}?${qs}`,
    );
    const data = unwrap(res);
    return {
      items: (data?.items ?? []).filter(d => d.isActive !== false),
      totalCount: data?.totalCount ?? data?.total ?? 0,
      page: data?.page ?? 1,
      pageSize: data?.pageSize ?? 20,
    };
  },
};
