export function mapBankLinesFromDto(
  rows?: Array<{
    id?: string;
    bankName: string;
    accountNumber: string;
    branchName?: string;
    isPrimary: boolean;
    sortOrder: number;
  }>,
): EmployeeBankAccountLine[] {
  return (rows ?? []).map(r => ({
    id: r.id,
    bankName: r.bankName,
    accountNumber: r.accountNumber,
    branchName: r.branchName,
    isPrimary: r.isPrimary,
    sortOrder: r.sortOrder,
  }));
}

