export function ensureSalaryLinesFromEmployee(emp: {
  joinDate?: string;
  createdAt?: string;
  baseSalary?: number;
  contractSalary?: number;
  positionAllowance?: number;
  lunchAllowance?: number;
  salaryLines?: Array<{
    id?: string;
    effectiveFrom: string;
    effectiveTo?: string;
    baseSalary: number;
    contractSalary: number;
    positionAllowance: number;
    lunchAllowance: number;
    note?: string;
    sortOrder: number;
  }>;
}): EmployeeSalaryLine[] {
  const mapped = mapSalaryLinesFromDto(emp.salaryLines);
  if (mapped.length > 0) return mapped;

  const hasHeaderSalary =
    (emp.baseSalary ?? 0) > 0
    || (emp.contractSalary ?? 0) > 0
    || (emp.positionAllowance ?? 0) > 0
    || (emp.lunchAllowance ?? 0) > 0;

  if (!hasHeaderSalary) return [];

  const effectiveFrom = emp.joinDate?.slice(0, 10) || emp.createdAt?.slice(0, 10) || '';
  if (!effectiveFrom) return [];

  return [
    {
      effectiveFrom,
      effectiveTo: '',
      baseSalary: emp.baseSalary ?? 0,
      contractSalary: emp.contractSalary ?? 0,
      positionAllowance: emp.positionAllowance ?? 0,
      lunchAllowance: emp.lunchAllowance ?? 0,
      note: '',
      sortOrder: 0,
    },
  ];
}

