export function pickCurrentSalaryLine(rows: EmployeeSalaryLine[]): EmployeeSalaryLine | undefined {
  if (rows.length === 0) return undefined;
  const today = new Date().toISOString().slice(0, 10);
  const current = rows
    .filter(r => r.effectiveFrom && r.effectiveFrom <= today && (!r.effectiveTo || r.effectiveTo >= today))
    .sort((a, b) => b.effectiveFrom.localeCompare(a.effectiveFrom))[0];
  return current ?? [...rows].sort((a, b) => b.effectiveFrom.localeCompare(a.effectiveFrom))[0];
}

export function countActiveDependents(rows: EmployeeDependentLine[]): number {
  const today = new Date().toISOString().slice(0, 10);
  return rows.filter(
    r =>
      r.isRegistered
      && r.registrationFrom
      && r.registrationFrom <= today
      && (!r.registrationTo || r.registrationTo >= today),
  ).length;
}
