import React, { useMemo } from 'react';
import { SearchInput } from '@linm-soft-org/linm-web-common-components';
import { useDepartmentCatalogSearchConfig } from '../../../hooks/useDepartmentCatalogSearchConfig';
import { DEPARTMENT_FIELD_LABEL } from '../../../utils/departmentField';

type Props = {
  departmentId: string;
  departmentCode?: string;
  departmentName?: string;
  disabled?: boolean;
  onChange: (id: string, code: string, name: string) => void;
  onClear: () => void;
  testId?: string;
  showLabel?: boolean;
};

export const DepartmentLookupField: React.FC<Props> = ({
  departmentId,
  departmentCode,
  departmentName,
  disabled,
  onChange,
  onClear,
  testId,
  showLabel = false,
}) => {
  const { config, loading } = useDepartmentCatalogSearchConfig();

  const primaryDisplay = useMemo(() => {
    if (!departmentId) return '';
    if (departmentCode && departmentName) return `${departmentCode} — ${departmentName}`;
    return departmentName ?? departmentCode ?? '';
  }, [departmentId, departmentCode, departmentName]);

  const field = (
    <SearchInput
      config={
        config ?? {
          api: {
            getItemKey: item => item.id,
            search: async () => ({ items: [], page: 1, totalPages: 1 }),
          },
          display: {
            getPrimaryDisplay: item => item.code,
            getSecondaryDisplay: item => item.name,
          },
          columns: [],
          header: { columns: [] },
          texts: { empty: 'Đang tải...' },
        }
      }
      value={departmentId}
      primaryDisplay={primaryDisplay}
      onChange={item => onChange(item.id, item.code, item.name)}
      onClear={onClear}
      disabled={disabled || loading || !config}
      showLabel={false}
      showSecondaryInput={false}
      placeholder={loading ? 'Đang tải...' : 'Mã hoặc tên phòng ban...'}
      data-testid={testId}
    />
  );

  if (!showLabel) return field;

  return (
    <div>
      <label>{DEPARTMENT_FIELD_LABEL}</label>
      {field}
    </div>
  );
};
