import { useEffect, useMemo, useState } from 'react';
import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { useCatalogSearchConfig } from '../components/catalog/catalogUiSchema/useCatalogSearchConfig';
import { createStaticLookupSearchConfig } from '../components/search/createStaticLookupSearchConfig';
import {
  departmentCatalogEndpoint,
  type DepartmentCatalogRow,
} from '../services/catalog/departmentCatalogEndpoint';

export const DEPARTMENTS_CATALOG_KIND = 'departments';
/** Dưới ngưỡng → filter client; từ ngưỡng → search remote `/master/departments`. */
export const DEPARTMENT_STATIC_LOOKUP_LIMIT = 50;

export function useDepartmentCatalogSearchConfig(): {
  config: SearchInputConfig<DepartmentCatalogRow> | null;
  loading: boolean;
} {
  const [mode, setMode] = useState<'loading' | 'static' | 'remote'>('loading');
  const [staticItems, setStaticItems] = useState<DepartmentCatalogRow[]>([]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      departmentCatalogEndpoint
        .getList({ page: 1, pageSize: 1 })
        .then(probe => {
          if (cancelled) return;
          if (probe.totalCount < DEPARTMENT_STATIC_LOOKUP_LIMIT) {
            return departmentCatalogEndpoint
              .getList({ page: 1, pageSize: DEPARTMENT_STATIC_LOOKUP_LIMIT })
              .then(full => {
                if (!cancelled) {
                  setStaticItems(full.items);
                  setMode('static');
                }
              });
          }
          setMode('remote');
        })
        .catch(() => {
          if (!cancelled) setMode('remote');
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const remoteSearch = useMemo(
    () => async (params: { search?: string; page?: number; pageSize?: number }) =>
      departmentCatalogEndpoint.getList(params),
    [],
  );

  const { config: remoteConfig, loading: remoteSchemaLoading } = useCatalogSearchConfig(
    DEPARTMENTS_CATALOG_KIND,
    remoteSearch,
    item => item.id,
    {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
  );

  const staticConfig = useMemo(() => {
    if (mode !== 'static' || staticItems.length === 0) return null;
    return createStaticLookupSearchConfig<DepartmentCatalogRow>({
      loadItems: () => staticItems,
      getKey: item => item.id,
      getCode: item => item.code,
      getName: item => item.name,
      getFilterText: item => `${item.code} ${item.name}`,
    });
  }, [mode, staticItems]);

  const fallbackRemoteConfig = useMemo(
    (): SearchInputConfig<DepartmentCatalogRow> => ({
      api: {
        getItemKey: item => item.id,
        search: async ({ search, page, pageSize }) => {
          const data = await departmentCatalogEndpoint.getList({ search, page, pageSize });
          const size = data.pageSize || 20;
          const totalPages = Math.max(1, Math.ceil(data.totalCount / size));
          return { items: data.items, page: data.page, totalPages };
        },
      },
      display: {
        getPrimaryDisplay: item => item.code,
        getSecondaryDisplay: item => item.name,
        getSingleDisplay: item => `${item.code} — ${item.name}`,
      },
      dropdownPortal: true,
      texts: { empty: 'Không tìm thấy phòng ban' },
    }),
    [],
  );

  if (mode === 'loading') {
    return { config: null, loading: true };
  }
  if (mode === 'static') {
    return { config: staticConfig, loading: false };
  }
  return {
    config: remoteConfig ?? fallbackRemoteConfig,
    loading: remoteSchemaLoading,
  };
}
